item.content:encoded:
body{font-family: "WenQuanYi Zen Hei",Helvetica,"Heiti TC","LiHei Pro", "Microsoft JhengHei","Segoe UI Semibold", "Lucida Grande","Segoe UI",   Arial,sans-serif;}
p {
	font-size:1.2em;
	letter-spacing: 0.2em;
	color:#000000;
	font-weight: 300;
	line-height: 1.6em;
	margin:0 0 .8em 0;
}
ul, ol {font-size:1.em;
	letter-spacing: 0.2em;
	color:#000000;
}
.site-nav a:link {
    font-size: 1em;
	line-height: 1.5em;
	letter-spacing: 0.1em;
	text-decoration: none;
}
.post-inner.section-inner{max-width:85%}
.site-description{	font-size:1em;font-weight:600;letter-spacing:0.01em;text-align:justify;
}
.theChampTotalShareText {font-size:0.8em !important;letter-spacing:0.05em;text-transform:uppercase}

.navbar .navbar-nav>li a {
    font-size: 1.5em;
}
.page-header{
height: 60vh !important;
}
.page-header.header-small .container .hestia-title, .page-header.header-small .container .title {
    margin: 15vh 0 10px;
}

{"styles":{"color":{"background":"#faffff","text":"#333333"},"css":":where(.wp-site-blocks *:focus){outline-width:2px;outline-style:solid}

.grecaptcha-badge { visibility: hidden; }

a:hover {
padding:2px;
 background-color: rgba(255, 255, 255, 0.1); /* 背景變淡藍 */
 box-shadow: 0px 2px 4px rgba(0, 0, 0, 0.2); /* 增加陰影效果 */
}

/* 僅限內容文章的連結加上底線 */
.entry-content a, 
.post-content a {
 text-decoration: underline;
}

/* 基本輸入框樣式 */
.wpcf7 input[type="text"],
.wpcf7 input[type="email"],
.wpcf7 input[type="url"],
.wpcf7 textarea {
 width: 100%;
 padding: 12px 15px;
 margin: 8px 0;
 box-sizing: border-box;
 border: 1px solid #ccc;
 border-radius: 4px;
 background-color: #f8f8f8;
 font-size: 16px;
 color: #333;
 transition: border 0.3s ease, background-color 0.3s ease;
}

/* 輸入框獲得焦點時的樣式 */
.wpcf7 input[type="text"]:focus,
.wpcf7 input[type="email"]:focus,
.wpcf7 input[type="url"]:focus,
.wpcf7 textarea:focus {
 border: 1px solid #007bff;
 background-color: #fff;
 outline: none;
 box-shadow: 0 0 5px rgba(0, 123, 255, 0.5);
}

/* 初始狀態的提交按鈕 */
.wpcf7 input[type="submit"]:disabled {
 color: #ffffff;
 font-size: 16px;
 font-weight: 300;
 background: #dcdcdc; /* 灰色背景 */
 padding: 8px;
 border: none;
 border-radius: 5px;
 width: auto;
 text-transform: uppercase;
 letter-spacing: 5px;
 cursor: not-allowed; /* 禁用狀態 */
}

/* 同意鈕被勾選後的提交按鈕 */
.wpcf7 input[type="submit"]:enabled {
 color: #ffffff;
 font-size: 16px;
 font-weight: 300;
 background: #565656; /* 灰色背景 */
 padding: 8px;
 border: none;
 border-radius: 5px;
 width: auto;
 text-transform: uppercase;
 letter-spacing: 5px;
 cursor: default; /* 指針狀態 */
}

/* 提交按鈕的懸停效果 */
.wpcf7 input[type="submit"]:enabled:hover {
 background: #383838;
 transition: all 0.4s ease 0s;
}

/* 提交按鈕的按下效果 */
.wpcf7 input[type="submit"]:enabled:active {
 background: #000000;
}
